# Special registers and s_waitcnt wait-counters, keyed by lowercased operand token.
# Hand-maintained from the AMD "RDNA3.5" ISA reference (ch. 3 registers, sec. 5.6
# data dependency resolution). Shown as a hover tooltip when the cursor is over one
# of these operand tokens (e.g. lgkmcnt in "s_waitcnt lgkmcnt(0)"). Pure ASCII.
REG_GLOSSARY = {
"vmcnt": "Vector-memory LOAD counter (6-bit). Counts VMEM load/sample instructions (texture/buffer/global/scratch/flat loads + atomics-with-return) issued but not yet completed. s_waitcnt vmcnt(N) blocks until <= N remain; loads may complete out of order.",
"vscnt": "Vector-memory STORE counter (6-bit). Counts VMEM stores and atomics-without-return issued but not yet completed. Waited via s_waitcnt_vscnt; kept separate from vmcnt so loads and stores are tracked independently.",
"lgkmcnt": "LDS/GDS/Konstant/Message counter (6-bit). Counts LDS, GDS/GWS, constant-fetch (scalar SMEM reads), and message instructions issued but not yet completed. These can finish out of order, so the only safe use is s_waitcnt lgkmcnt(0). FLAT ops bump this and vmcnt/vscnt.",
"expcnt": "Export counter (3-bit). Counts Export and GDS-write instructions issued but not yet completed; also counts outstanding LDS parameter/direct loads. s_waitcnt expcnt(N) blocks until <= N remain.",
"scc": "Scalar Condition Code (1 bit). Result flag set by most SALU ops: carry-out, signed overflow, nonzero result, or a scalar-compare result. Read by s_cbranch_scc0/scc1 and used as carry-in.",
"exec": "Execute mask (64-bit, EXEC_LO/EXEC_HI). One bit per lane selecting which work-items of the wave run vector instructions; inactive lanes are skipped. EXECZ flags all-zero.",
"exec_lo": "Low 32 bits of the 64-bit EXECute mask (lanes 0-31).",
"exec_hi": "High 32 bits of the 64-bit EXECute mask (lanes 32-63).",
"vcc": "Vector Condition Code (64-bit, VCC_LO/VCC_HI). One bit per lane holding v_cmp results and add/sub carry-out; used as the condition for v_cndmask and divergent branches. Physically resides in a specific SGPR pair.",
"vcc_lo": "Low 32 bits of the 64-bit Vector Condition Code (lanes 0-31).",
"vcc_hi": "High 32 bits of the 64-bit Vector Condition Code (lanes 32-63).",
"m0": "M0 (32-bit misc register). Temporary scalar used as an implicit operand/index by certain instructions: LDS/GDS addressing, s_sendmsg, indexed GPR moves, etc. Writable only by the scalar ALU.",
"null": "The NULL register: reads as zero and discards writes. Used as a placeholder source or destination.",
"execz": "Single-bit flag: set when the entire EXEC mask is zero (no lanes active). Usable as a branch condition.",
"vccz": "Single-bit flag: set when the entire VCC mask is zero.",
}


# GPU / quantization concepts (not ISA opcodes or registers), keyed by a lowercased
# term. Used for hover/help captions in the schematic and detail panels. Pure ASCII.
CONCEPT_GLOSSARY = {
"superblock": (
    "K-quant super-block: the 256-weight (QK_K=256) container ggml uses to store "
    "k-quantized weights. Not just packed quants -- it carries a two-level scale "
    "hierarchy: one fp16 super-block scale (and, for Q4_K/Q5_K, an fp16 min) plus "
    "cheap per-sub-block scales. The 256 weights split into sub-blocks that each "
    "get their own quantized scale, so dequant is weight = d*sub_scale*q (- dmin* "
    "sub_min for Q4/Q5_K); the two tiers give k-quants better accuracy than type-0 "
    "quants at nearly the same bit rate (hence 'K'). Per-super-block bytes: "
    "Q4_K=144 (8 sub-blocks x32, 6-bit scale+min, 4.5 bpw), Q5_K=176 (adds a 32B "
    "high-bit plane, 5.5 bpw), Q6_K=210 (16 sub-blocks x16, 8-bit scale, no min, "
    "6.56 bpw). A mmvq reduction over K walks K/256 super-blocks per output row."
),
}
